@dataclass
class Tetromino:
    type: TetrominoType
    rotation: int = 0         # 0-3 index into rotation states
    x: int = 0                # column position of pivot
    y: int = 0                # row position of pivot

    def current_blocks(self) -> List[Tuple[int,int]]:
        shape = TETROMINO_SHAPES[self.type][self.rotation % 4]
        return [(self.x + dx, self.y + dy) for dx, dy in shape]

    def rotate(self, clockwise: bool = True) -> None:
        self.rotation = (self.rotation + (1 if clockwise else -1)) % 4

# Game Grid
class Grid:
    def __init__(self, width: int = 10, height: int = 20):
        self.width: int = width
        self.height: int = height
        self.cells: List[List[Optional[Gem]]] = [
            [None for _ in range(self.width)] for _ in range(self.height)
        ]

    def in_bounds(self, x: int, y: int) -> bool:
        return 0 <= x < self.width and 0 <= y < self.height

    def get_cell(self, x: int, y: int) -> Optional[Gem]:
        if not self.in_bounds(x, y):
            return None
        return self.cells[y][x]

    def set_cell(self, x: int, y: int, gem: Optional[Gem]) -> None:
        if self.in_bounds(x, y):
            self.cells[y][x] = gem

    def clear_cell(self, x: int, y: int) -> None:
        if self.in_bounds(x, y):
            self.cells[y][x] = None

    def reset(self) -> None:
        for y in range(self.height):
            for x in range(self.width):
                self.cells[y][x] = None

    def is_position_valid(self, tetromino: Tetromino) -> bool:
        """Checks if the tetromino's current position is valid within the grid."""
        for x, y in tetromino.current_blocks():
            if not self.in_bounds(x, y) or self.get_cell(x, y) is not None:
                return False
        return True

    def lock_tetromino(self, tetromino: Tetromino) -> None:
        """Locks the tetromino into the grid, converting it to Gems."""
        color = random.choice(list(GemColor))  # Assign random color
        for x, y in tetromino.current_blocks():
            self.set_cell(x, y, Gem(color=color))

class TetrisBejeweledGame:
    def __init__(self, width: int = 10, height: int = 20):
        self.grid: Grid = Grid(width, height)
        self.current_tetromino: Optional[Tetromino] = None
        self.next_tetromino: Tetromino = self.create_tetromino()  # Generate the first next tetromino
        self.game_over: bool = False
        self.score: int = 0

    def create_tetromino(self) -> Tetromino:
        """Creates a new tetromino of a random type."""
        tetromino_type = random.choice(list(TetrominoType))
        return Tetromino(type=tetromino_type, x=self.grid.width // 2 - 1, y=0)

    def spawn_tetromino(self) -> bool:
        """Spawns a new tetromino at the top of the grid.

        Returns:
            True if the spawn was successful, False if the game is over.
        """
        self.current_tetromino = self.next_tetromino
        self.next_tetromino = self.create_tetromino()  # Generate the next one
        self.current_tetromino.x = self.grid.width // 2 - 1
        self.current_tetromino.y = 0
        if not self.grid.is_position_valid(self.current_tetromino):
            self.game_over = True
            return False
        return True

    def move_tetromino(self, dx: int) -> None:
        """Moves the current tetromino horizontally."""
        if self.current_tetromino is None:
            return
        self.current_tetromino.x += dx
        if not self.grid.is_position_valid(self.current_tetromino):
            self.current_tetromino.x -= dx  # Move back

    def move_tetromino_down(self) -> None:
        """Moves the current tetromino down by one cell."""
        if self.current_tetromino is None:
            return
        self.current_tetromino.y += 1
        if not self.grid.is_position_valid(self.current_tetromino):
            self.current_tetromino.y -= 1  # Move back
            self.lock_tetromino()  # Lock the tetromino if it hits something

    def rotate_tetromino(self, clockwise: bool = True) -> None:
        """Rotates the current tetromino."""
        if self.current_tetromino is None:
            return
        original_rotation = self.current_tetromino.rotation
        self.current_tetromino.rotate(clockwise)
        if not self.grid.is_position_valid(self.current_tetromino):
            self.current_tetromino.rotation = original_rotation  # Rotate back

    def lock_tetromino(self) -> None:
        """Locks the current tetromino into the grid and processes line/match clearing."""
        if self.current_tetromino is None:
            return

        self.grid.lock_tetromino(self.current_tetromino)
        self.current_tetromino = None
        self.clear_lines()
        self.clear_matches()

        if not self.spawn_tetromino():
            self.game_over = True

    def clear_lines(self) -> None:
        """Clears full lines in the grid (Tetris-style)."""
        lines_to_clear = []
        for y in range(self.grid.height):
            if all(self.grid.get_cell(x, y) is not None for x in range(self.grid.width)):
                lines_to_clear.append(y)

        for y in lines_to_clear:
            for x in range(self.grid.width):
                self.grid.clear_cell(x, y)

            # Shift down the lines above
            for yy in range(y - 1, -1, -1):
                for x in range(self.grid.width):
                    gem = self.grid.get_cell(x, yy)
                    self.grid.set_cell(x, yy + 1, gem)
                    self.grid.set_cell(x, yy, None)  # Clear the old cell

        if lines_to_clear:
            num_lines = len(lines_to_clear)
            self.score += self.calculate_line_clear_score(num_lines)

    def calculate_line_clear_score(self, num_lines: int) -> int:
        """Calculates score based on the number of lines cleared."""
        line_clear_scores = {
            1: 40,
            2: 100,
            3: 300,
            4: 1200,
        }
        return line_clear_scores.get(num_lines, 0)

    def clear_matches(self) -> None:
        """Clears 3 or more adjacent gems of the same color (Bejeweled-style)."""
        matches = self.find_matches()
        if matches:
            self.remove_matches(matches)
            self.score += self.calculate_match_score(len(matches))  # Update score based on matches
            self.drop_gems()  # Gems fall to fill empty spaces
            self.clear_matches()  # Check for cascading matches

    def find_matches(self) -> List[Tuple[int, int]]:
        """Finds all matches of 3 or more adjacent gems of the same color."""
        matches: List[Tuple[int, int]] = []
        width, height = self.grid.width, self.grid.height
        cells = self.grid.cells

        # Helper function to check for matches in a line (horizontal or vertical)
        def find_line_matches(line: List[Optional[Gem]]) -> List[int]:
            line_matches: List[int] = []
            if not line:
                return line_matches

            count = 1
            start_index = 0
            for i in range(1, len(line)):
                if line[i] is not None and line[i - 1] is not None and line[i].color == line[i - 1].color:
                    count += 1
                else:
                    if count >= 3:
                        line_matches.extend(range(start_index, i))
                    count = 1
                    start_index = i

            if count >= 3:
                line_matches.extend(range(start_index, len(line)))

            return line_matches

        # Check horizontal matches
        for y in range(height):
            row = [cells[y][x] for x in range(width)]
            horizontal_matches = find_line_matches(row)
            matches.extend((x, y) for x in horizontal_matches)

        # Check vertical matches
        for x in range(width):
            col = [cells[y][x] for y in range(height)]
            vertical_matches = find_line_matches(col)
            matches.extend((x, y) for y in vertical_matches)

        # Remove duplicate matches
        unique_matches = list(set(matches))
        return unique_matches

    def remove_matches(self, matches: List[Tuple[int, int]]) -> None:
        """Removes the given matches from the grid."""
        for x, y in matches:
            self.grid.clear_cell(x, y)

    def calculate_match_score(self, num_matches: int) -> int:
        """Calculates the score for a given number of matches."""
        return num_matches * 10  # Base score, can be adjusted

    def drop_gems(self) -> None:
        """Drops gems down to fill empty spaces."""
        width, height = self.grid.width, self.grid.height
        cells = self.grid.cells

        for x in range(width):
            empty_pos = -1
            for y in range(height - 1, -1, -1):
                if cells[y][x] is None and empty_pos == -1:
                    empty_pos = y
                elif cells[y][x] is not None and empty_pos != -1:
                    # Move the gem to the empty position
                    cells[empty_pos][x] = cells[y][x]
                    cells[y][x] = None
                    empty_pos -= 1
